import{_ as a,o as t,c as o,aj as r}from"./chunks/framework.DNJ2HNkG.js";const E=JSON.parse('{"title":"ESXi 7.0U2驱动海康威视C2000 Pro方法","description":"","frontmatter":{"title":"ESXi 7.0U2驱动海康威视C2000 Pro方法","date":"2021-04-06T09:19:56.000Z","category":"ESXi","tags":["ESXi"]},"headers":[],"relativePath":"posts/ESXi 7.0U2驱动海康威视C2000 Pro方法.md","filePath":"posts/ESXi 7.0U2驱动海康威视C2000 Pro方法.md","lastUpdated":1783047625000}'),i={name:"posts/ESXi 7.0U2驱动海康威视C2000 Pro方法.md"};function s(p,e,c,l,d,n){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h1><p>ESXi 发布了7.0U2版本，bug比之前少了不少，准备尝试下，安装后发现海康威视的C2000 Pro驱动不起来，如果用之前6.7的方法，降级2个驱动，就不认网卡了。</p><h1 id="方法" tabindex="-1">方法 <a class="header-anchor" href="#方法" aria-label="Permalink to &quot;方法&quot;">​</a></h1><p>研究测试了下，直接用6.5u2的nvme驱动包替换就可以了。</p><p>1、下载 <code>VMware-VMvisor-Installer-6.5.0.update02-8294253.x86_64.iso</code>，用Dell的OEM镜像也可以 <a href="https://www.dell.com/support/home/zh-hk/drivers/driversdetails?driverid=ckc15" target="_blank" rel="noreferrer">VMware-VMvisor-Installer-6.5.0.update02-8294253.x86_64-DellEMC_Customized-A00.iso</a></p><p>2、ESXi 7.0U2打开ssh，进入<code>/bootbank</code>目录，备份<code>nvme_pci.v00</code>为<code>nvme_pci.v00.bak</code></p><p>3、挂载ISO，复制ISO中的<code>NVME.V00</code>到<code>/bootbank</code>目录并重命名为<code>nvme_pci.v00</code></p><p>4、重启</p><p>正确识别，可以使用。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_7.0U2%E9%A9%B1%E5%8A%A8%E6%B5%B7%E5%BA%B7%E5%A8%81%E8%A7%86C2000_Pro%E6%96%B9%E6%B3%95/1617673961681.png" alt=""></p><h1 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h1><p>如果只有一块SSD，可以直接封装进ISO，这样安装时候就可以识别。</p><p>海康威视的SSD没有写 WWN 码，原因自己想，但价格和质保确实挺香，作为游戏盘或者不重要的数据盘，性价比还是很高的，挂了就售后换新。</p><p>如果不是从6.7升级到7.0，ESXi 7.x新安装会自动新建一个VMFS-L分区，会占用一部分磁盘空间，解决方法可以看前一篇博文 <a href="https://blog.white-alone.com/ESXi%20%E5%B0%81%E8%A3%85I219V%E7%BD%91%E5%8D%A1%E9%A9%B1%E5%8A%A8/" target="_blank" rel="noreferrer">《ESXi 封装I219V网卡驱动》</a></p><p>最后，升级到7.0U2后，MacOS解锁patch用<a href="https://blog.white-alone.com/ESXi%20%E5%B0%81%E8%A3%85I219V%E7%BD%91%E5%8D%A1%E9%A9%B1%E5%8A%A8/" target="_blank" rel="noreferrer">《ESXi 封装I219V网卡驱动》</a>里的就可以</p>',14)])])}const h=a(i,[["render",s]]);export{E as __pageData,h as default};
